  // ─── 5. DIFFERENTIATION INTEGRATION KINEMATIC LINKS ──────────────────────
  static differentiationIntegrationKinematicLinksDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 400">

  <text x="100" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Calculus Links in Kinematics — Differentiation &amp; Integration</text>

  <!-- Three main boxes: position, velocity, acceleration -->
  <!-- Box 1: Position s(t) -->
  <rect x="50" y="130" width="140" height="70" rx="8" fill="none" stroke="#000" stroke-width="3"/>
  <text x="84" y="158" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Position</text>
  <text x="96" y="178" font-family="Georgia,serif" font-size="13" font-style="italic" fill="#000">s(t)</text>
  <text x="64" y="192" font-family="Georgia,serif" font-size="9" fill="#000">[metres, m]</text>

  <!-- Box 2: Velocity v(t) -->
  <rect x="210" y="130" width="140" height="70" rx="8" fill="none" stroke="#000" stroke-width="3"/>
  <text x="245" y="158" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Velocity</text>
  <text x="256" y="178" font-family="Georgia,serif" font-size="13" font-style="italic" fill="#000">v(t)</text>
  <text x="222" y="192" font-family="Georgia,serif" font-size="9" fill="#000">[metres per second]</text>

  <!-- Box 3: Acceleration a(t) -->
  <rect x="370" y="130" width="140" height="70" rx="8" fill="none" stroke="#000" stroke-width="3"/>
  <text x="390" y="158" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Acceleration</text>
  <text x="406" y="178" font-family="Georgia,serif" font-size="13" font-style="italic" fill="#000">a(t)</text>
  <text x="382" y="192" font-family="Georgia,serif" font-size="9" fill="#000">[metres per second²]</text>

  <!-- Differentiation arrows (left to right, above) -->
  <!-- s → v -->
  <line x1="190" y1="148" x2="210" y2="148" stroke="#000" stroke-width="3"/>
  <polygon points="206,143 218,148 206,153" fill="#000"/>
  <text x="190" y="136" font-family="Georgia,serif" font-size="10" fill="#000">d/dt</text>
  <text x="185" y="124" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">differentiate →</text>

  <!-- v → a -->
  <line x1="350" y1="148" x2="370" y2="148" stroke="#000" stroke-width="3"/>
  <polygon points="366,143 378,148 366,153" fill="#000"/>
  <text x="350" y="136" font-family="Georgia,serif" font-size="10" fill="#000">d/dt</text>
  <text x="345" y="124" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">differentiate →</text>

  <!-- Integration arrows (right to left, below) -->
  <!-- a → v -->
  <line x1="370" y1="215" x2="350" y2="215" stroke="#000" stroke-width="3"/>
  <polygon points="354,210 342,215 354,220" fill="#000"/>
  <text x="340" y="234" font-family="Georgia,serif" font-size="10" fill="#000">∫ dt</text>
  <text x="330" y="248" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">← integrate</text>

  <!-- v → s -->
  <line x1="210" y1="215" x2="190" y2="215" stroke="#000" stroke-width="3"/>
  <polygon points="194,210 182,215 194,220" fill="#000"/>
  <text x="180" y="234" font-family="Georgia,serif" font-size="10" fill="#000">∫ dt</text>
  <text x="168" y="248" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">← integrate</text>

  <!-- Double differentiation s → a (curved arrow, below) -->
  <path d="M 120,200 Q 280,270 440,200" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="6,4"/>
  <polygon points="436,196 448,198 438,206" fill="#000"/>
  <text x="240" y="266" font-family="Georgia,serif" font-size="10" fill="#000">d²s/dt² = a</text>

  <!-- Worked example box -->
  <rect x="50" y="295" width="460" height="90" rx="5" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="60" y="314" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Worked example:   s(t) = 3t³ − 2t² + 5</text>
  <line x1="60" y1="320" x2="500" y2="320" stroke="#000" stroke-width="1"/>
  <text x="60" y="336" font-family="Georgia,serif" font-size="10" fill="#000">v(t) = ds/dt = 9t² − 4t</text>
  <text x="60" y="352" font-family="Georgia,serif" font-size="10" fill="#000">a(t) = dv/dt = 18t − 4</text>
  <text x="60" y="368" font-family="Georgia,serif" font-size="10" fill="#000">∫v dt = ∫(9t²−4t)dt = 3t³ − 2t² + C  =  s(t) + C   ✓</text>
  <text x="60" y="378" font-family="Georgia,serif" font-size="9" fill="#444">Constant of integration C determined from initial conditions (e.g. s₀ at t=0)</text>

  <!-- Graph mini-sketches to illustrate -->
  <!-- s-t cubic curve hint -->
  <text x="50" y="90" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">s(t)</text>
  <path d="M 50,110 C 70,115 80,80 100,70" fill="none" stroke="#000" stroke-width="2"/>
  <!-- v-t parabola hint -->
  <text x="210" y="90" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">v(t)</text>
  <path d="M 210,110 Q 240,60 270,110" fill="none" stroke="#000" stroke-width="2"/>
  <!-- a-t line hint -->
  <text x="370" y="90" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">a(t)</text>
  <line x1="370" y1="100" x2="450" y2="80" stroke="#000" stroke-width="2"/>
</svg>`;

