  // ─── 7. X-RAY DIFFRACTION — BRAGG'S LAW ──────────────────────────────────
  static xrayDiffractionBraggPlanesCrystalLatticeSpacingDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 400">

  <!-- Title -->
  <text x="90" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">X-Ray Diffraction — Bragg's Law and Crystal Planes</text>
  <text x="110" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Constructive interference when 2d sinθ = nλ</text>

  <!-- ── Crystal lattice planes (3 horizontal planes) ── -->
  <!-- Plane 1: y=140 -->
  <line x1="40" y1="140" x2="520" y2="140" stroke="#000" stroke-width="2.5" stroke-dasharray="8,4"/>
  <!-- Plane 2: y=200 -->
  <line x1="40" y1="200" x2="520" y2="200" stroke="#000" stroke-width="2.5" stroke-dasharray="8,4"/>
  <!-- Plane 3: y=260 -->
  <line x1="40" y1="260" x2="520" y2="260" stroke="#000" stroke-width="2.5" stroke-dasharray="8,4"/>

  <!-- Plane labels -->
  <text x="522" y="144" font-family="Georgia,serif" font-size="10" fill="#000">Plane 1</text>
  <text x="522" y="204" font-family="Georgia,serif" font-size="10" fill="#000">Plane 2</text>
  <text x="522" y="264" font-family="Georgia,serif" font-size="10" fill="#000">Plane 3</text>

  <!-- Crystal atom dots on planes -->
  <!-- Plane 1 atoms -->
  <circle cx="80"  cy="140" r="5" fill="#000"/>
  <circle cx="140" cy="140" r="5" fill="#000"/>
  <circle cx="200" cy="140" r="5" fill="#000"/>
  <circle cx="260" cy="140" r="5" fill="#000"/>
  <circle cx="320" cy="140" r="5" fill="#000"/>
  <circle cx="380" cy="140" r="5" fill="#000"/>
  <circle cx="440" cy="140" r="5" fill="#000"/>
  <circle cx="500" cy="140" r="5" fill="#000"/>
  <!-- Plane 2 atoms -->
  <circle cx="80"  cy="200" r="5" fill="#000"/>
  <circle cx="140" cy="200" r="5" fill="#000"/>
  <circle cx="200" cy="200" r="5" fill="#000"/>
  <circle cx="260" cy="200" r="5" fill="#000"/>
  <circle cx="320" cy="200" r="5" fill="#000"/>
  <circle cx="380" cy="200" r="5" fill="#000"/>
  <circle cx="440" cy="200" r="5" fill="#000"/>
  <circle cx="500" cy="200" r="5" fill="#000"/>
  <!-- Plane 3 atoms -->
  <circle cx="80"  cy="260" r="5" fill="#000"/>
  <circle cx="140" cy="260" r="5" fill="#000"/>
  <circle cx="200" cy="260" r="5" fill="#000"/>
  <circle cx="260" cy="260" r="5" fill="#000"/>
  <circle cx="320" cy="260" r="5" fill="#000"/>
  <circle cx="380" cy="260" r="5" fill="#000"/>
  <circle cx="440" cy="260" r="5" fill="#000"/>
  <circle cx="500" cy="260" r="5" fill="#000"/>

  <!-- d-spacing bracket (between plane 1 and 2) -->
  <!-- L-bracket left side -->
  <line x1="52" y1="140" x2="52" y2="200" stroke="#000" stroke-width="2"/>
  <line x1="48" y1="140" x2="56" y2="140" stroke="#000" stroke-width="2"/>
  <line x1="48" y1="200" x2="56" y2="200" stroke="#000" stroke-width="2"/>
  <text x="20" y="175" font-family="Georgia,serif" font-size="12" font-style="italic" font-weight="bold" fill="#000">d</text>
  <text x="18" y="187" font-family="Georgia,serif" font-size="9" fill="#000">(spacing)</text>

  <!-- ── Incident X-ray beams (two rays striking plane 1 and plane 2) ──
       Angle theta from planes. Incident from upper-left.
       Ray 1: hits plane 1 at (260,140)
       Ray 2: hits plane 2 at (290,200) — slightly offset to show path difference
  -->
  <!-- Ray 1 incident: from (180,60) to (260,140) -->
  <line x1="180" y1="60" x2="260" y2="140" stroke="#000" stroke-width="3"/>
  <polygon points="254,134 260,140 264,132" fill="#000"/>

  <!-- Ray 2 incident: from (210,60) to (290,200) -->
  <line x1="210" y1="60" x2="290" y2="200" stroke="#000" stroke-width="3"/>
  <polygon points="284,194 290,200 294,192" fill="#000"/>

  <!-- Ray 1 reflected: from (260,140) to (340,60) -->
  <line x1="260" y1="140" x2="340" y2="60" stroke="#000" stroke-width="3"/>
  <polygon points="334,66 340,60 336,68" fill="#000"/>

  <!-- Ray 2 reflected: from (290,200) to (370,120) → continues to (410,60) -->
  <!-- Slope of reflection same as incident (symmetric about plane normal) -->
  <!-- incident direction: (80,140) → angle from horizontal = 45° for simplicity -->
  <!-- Reflected goes upper-right symmetrically -->
  <line x1="290" y1="200" x2="410" y2="60" stroke="#000" stroke-width="3"/>
  <polygon points="404,66 410,60 406,68" fill="#000"/>

  <!-- Theta angle arc at plane 1 intersection -->
  <path d="M 235,140 A 26,26 0 0,1 260,116" fill="none" stroke="#000" stroke-width="1.8"/>
  <text x="228" y="132" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">θ</text>

  <path d="M 260,116 A 26,26 0 0,1 285,140" fill="none" stroke="#000" stroke-width="1.8"/>
  <text x="272" y="128" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">θ</text>

  <!-- Path difference annotation: the extra path for ray 2 -->
  <!-- foot of perpendicular from ray1 to ray2 path on plane2 -->
  <!-- Extra path = 2d sinθ, shown as bracket below plane 2 intersection -->
  <!-- Drop perpendicular from (260,140) to ray2 extension and from (410,60) line -->
  <!-- Annotate path difference line segment at plane 2 -->
  <line x1="245" y1="200" x2="305" y2="200" stroke="#000" stroke-width="1" stroke-dasharray="3,2"/>
  <!-- Foot of perpendicular from ray1 incidence point to plane 2 -->
  <line x1="260" y1="140" x2="260" y2="200" stroke="#000" stroke-width="1.5" stroke-dasharray="4,3"/>
  <line x1="290" y1="140" x2="290" y2="200" stroke="#000" stroke-width="1.5" stroke-dasharray="4,3"/>

  <!-- Path difference bracket below plane 2 -->
  <line x1="260" y1="210" x2="290" y2="210" stroke="#000" stroke-width="1.5"/>
  <polygon points="264,206 254,210 264,214" fill="#000"/>
  <polygon points="286,206 296,210 286,214" fill="#000"/>
  <text x="262" y="225" font-family="Georgia,serif" font-size="9" fill="#000">d sinθ</text>

  <!-- Mirror path difference bracket (other side) — symmetric -->
  <text x="220" y="225" font-family="Georgia,serif" font-size="9" fill="#000">d sinθ</text>
  <text x="214" y="240" font-family="Georgia,serif" font-size="9" fill="#000">∴ total = 2d sinθ</text>

  <!-- ── Bragg formula box ── -->
  <rect x="340" y="200" width="200" height="80" rx="5" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="350" y="220" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Bragg's Law:</text>
  <text x="350" y="242" font-family="Georgia,serif" font-size="14" font-weight="bold" font-style="italic" fill="#000">2d sinθ = nλ</text>
  <text x="350" y="260" font-family="Georgia,serif" font-size="10" fill="#000">d = interplanar spacing</text>
  <text x="350" y="274" font-family="Georgia,serif" font-size="10" fill="#000">θ = glancing angle</text>

  <!-- Info box -->
  <rect x="30" y="305" width="500" height="80" rx="5" fill="none" stroke="#000" stroke-width="1.8" stroke-dasharray="5,3"/>
  <text x="42" y="323" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Applications of X-ray diffraction:</text>
  <text x="42" y="339" font-family="Georgia,serif" font-size="10" fill="#000">• Determination of crystal structure and lattice parameters (e.g. NaCl, DNA double helix)</text>
  <text x="42" y="355" font-family="Georgia,serif" font-size="10" fill="#000">• Identifies minerals, polymorphs; quality control in semiconductor fabrication</text>
  <text x="42" y="371" font-family="Georgia,serif" font-size="10" fill="#000">• Typical λ: 0.05–0.25 nm (X-rays) comparable to atomic spacings (~0.1–0.5 nm)</text>
</svg>`;


