  // ─── 19. LAB FRAME VS CENTRE-OF-MASS FRAME KINEMATIC REACTION ────────────
  static labFrameVersusCentreOfMassFrameKinematicReactionDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 420">

  <!-- Title -->
  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Lab Frame vs Centre-of-Mass Frame — Reaction Kinematics</text>
  <text x="90" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Transformation between frames; threshold energy; Jacobian for angular distributions</text>

  <!-- ══ LEFT: LAB FRAME ══ -->
  <text x="40" y="60" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">A. Laboratory Frame</text>

  <!-- Target at rest -->
  <circle cx="220" cy="150" r="28" fill="#d8d8d8" stroke="#000" stroke-width="3"/>
  <text x="207" y="147" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mₓ</text>
  <text x="205" y="162" font-family="Georgia,serif" font-size="9" fill="#555">at rest</text>

  <!-- Projectile moving right -->
  <circle cx="80" cy="150" r="20" fill="#e0e0e0" stroke="#000" stroke-width="2.5"/>
  <text x="71" y="155" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mₐ</text>
  <line x1="102" y1="150" x2="190" y2="150" stroke="#000" stroke-width="3"/>
  <polygon points="186,145 196,150 186,155" fill="#000"/>
  <text x="128" y="142" font-family="Georgia,serif" font-size="10" fill="#000">vₐ (lab)</text>
  <text x="58"  y="182" font-family="Georgia,serif" font-size="9" fill="#000">KE_a = T_a</text>

  <!-- After collision: products at angles in lab -->
  <!-- Product b at angle θ_L upward -->
  <circle cx="310" cy="100" r="18" fill="#e8e8e8" stroke="#000" stroke-width="2.5"/>
  <text x="302" y="105" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mb</text>
  <line x1="246" y1="137" x2="295" y2="107" stroke="#000" stroke-width="2.5"/>
  <polygon points="290,106 298,100 296,108" fill="#000"/>
  <!-- angle arc -->
  <path d="M 255,140 A 18,18 0 0,0 264,124" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,2"/>
  <text x="268" y="124" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">θ_L</text>

  <!-- Residual Y at angle φ_L downward -->
  <circle cx="310" cy="210" r="24" fill="#d0d0d0" stroke="#000" stroke-width="2.5"/>
  <text x="300" y="208" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mY</text>
  <line x1="246" y1="163" x2="290" y2="198" stroke="#000" stroke-width="2.5"/>
  <polygon points="286,196 292,204 286,204" fill="#000"/>
  <path d="M 256,162 A 18,18 0 0,1 264,178" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,2"/>
  <text x="268" y="182" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">φ_L</text>

  <!-- Velocity of CM -->
  <text x="40" y="250" font-family="Georgia,serif" font-size="10" fill="#000">v_cm = mₐvₐ / (mₐ + mₓ)</text>
  <text x="40" y="265" font-family="Georgia,serif" font-size="10" fill="#000">T_cm = ½μv²_rel  (μ = reduced mass)</text>
  <text x="40" y="280" font-family="Georgia,serif" font-size="9" fill="#555">T_th = −Q(1 + mₐ/mₓ)  (threshold lab KE)</text>

  <!-- ══ RIGHT: CM FRAME ══ -->
  <text x="360" y="60" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">B. Centre-of-Mass Frame</text>

  <!-- CM origin marker -->
  <circle cx="460" cy="155" r="5" fill="#000"/>
  <text x="466" y="155" font-family="Georgia,serif" font-size="9" fill="#000">CM</text>
  <!-- Cross hairs at CM -->
  <line x1="450" y1="155" x2="470" y2="155" stroke="#000" stroke-width="1.5"/>
  <line x1="460" y1="145" x2="460" y2="165" stroke="#000" stroke-width="1.5"/>

  <!-- Projectile moving right in CM -->
  <circle cx="380" cy="155" r="20" fill="#e0e0e0" stroke="#000" stroke-width="2.5"/>
  <text x="372" y="160" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mₐ</text>
  <line x1="402" y1="155" x2="453" y2="155" stroke="#000" stroke-width="2.5"/>
  <polygon points="449,150 457,155 449,160" fill="#000"/>
  <text x="414" y="147" font-family="Georgia,serif" font-size="9" fill="#000">p*_a →</text>

  <!-- Target moving left in CM -->
  <circle cx="540" cy="155" r="24" fill="#d8d8d8" stroke="#000" stroke-width="2.5"/>
  <text x="529" y="158" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mₓ</text>
  <line x1="516" y1="155" x2="469" y2="155" stroke="#000" stroke-width="2.5"/>
  <polygon points="474,150 466,155 474,160" fill="#000"/>
  <text x="482" y="147" font-family="Georgia,serif" font-size="9" fill="#000">← p*_x</text>

  <!-- After: products back-to-back in CM -->
  <!-- b upward-right -->
  <circle cx="505" cy="108" r="18" fill="#e8e8e8" stroke="#000" stroke-width="2.5"/>
  <text x="497" y="113" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mb</text>
  <line x1="466" y1="143" x2="490" y2="114" stroke="#000" stroke-width="2.5"/>
  <polygon points="486,115 494,108 493,116" fill="#000"/>
  <!-- angle label in CM -->
  <path d="M 472,148 A 16,16 0 0,0 480,134" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,2"/>
  <text x="482" y="133" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">θ*</text>

  <!-- Y downward-left (exactly opposite) -->
  <circle cx="416" cy="204" r="24" fill="#d0d0d0" stroke="#000" stroke-width="2.5"/>
  <text x="406" y="201" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">mY</text>
  <line x1="452" y1="168" x2="434" y2="194" stroke="#000" stroke-width="2.5"/>
  <polygon points="437,190 432,198 429,190" fill="#000"/>

  <!-- Back-to-back annotation -->
  <line x1="490" y1="114" x2="432" y2="194" stroke="#000" stroke-width="1" stroke-dasharray="3,3"/>
  <text x="464" y="168" font-family="Georgia,serif" font-size="9" fill="#000">180° apart</text>
  <text x="460" y="179" font-family="Georgia,serif" font-size="9" fill="#555">in CM frame</text>

  <!-- Transformation equation box -->
  <rect x="40" y="295" width="480" height="112" rx="5" fill="none" stroke="#000" stroke-width="1.8" stroke-dasharray="5,3"/>
  <text x="50" y="313" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Frame transformation (non-relativistic):</text>
  <text x="50" y="330" font-family="Georgia,serif" font-size="10" fill="#000">tan θ_L = sin θ* / (cos θ* + γ_cm)    where γ_cm = v_cm / v*_b</text>
  <text x="50" y="346" font-family="Georgia,serif" font-size="10" fill="#000">Jacobian: dσ/dΩ|_L = dσ/dΩ*|_CM · (1 + γ²_cm + 2γ_cm cos θ*)^(3/2) / |1 + γ_cm cos θ*|</text>
  <text x="50" y="362" font-family="Georgia,serif" font-size="10" fill="#000">Invariant: s = (Σ E)² − |Σ p|²c² = (mₐ+mₓ)²c⁴ + 2mₓTₐc² (Mandelstam)</text>
  <text x="50" y="378" font-family="Georgia,serif" font-size="10" fill="#000">Available energy in CM: √s − (mₐ+mₓ)c²; threshold: √s_min = (mb+mY)c²</text>
  <text x="50" y="393" font-family="Georgia,serif" font-size="9" fill="#555">Forward-backward asymmetry in lab arises from CM → lab boost; key for cross-section measurement</text>
</svg>`;

