  // ─── 22. EXPONENTIAL DECAY CURVE ─────────────────────────────────────────
  static exponentialDecayCurveNVsTimeWithHalfLifeMarkingssvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 480">

  <!-- Title -->
  <text x="70" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Exponential Decay — N vs Time with Half-Life Markings</text>
  <text x="90" y="38" font-family="Georgia,serif" font-size="10" fill="#444">N(t) = N₀ e^(−λt) = N₀ (1/2)^(t/t½)</text>

  <!-- ── AXES ── -->
  <line x1="70" y1="390" x2="530" y2="390" stroke="#000" stroke-width="2.5"/>
  <polygon points="524,385 536,390 524,395" fill="#000"/>
  <text x="500" y="410" font-family="Georgia,serif" font-size="11" fill="#000">Time (t)</text>

  <line x1="70" y1="390" x2="70" y2="60" stroke="#000" stroke-width="2.5"/>
  <polygon points="65,64 70,52 75,64" fill="#000"/>
  <text x="10" y="90" font-family="Georgia,serif" font-size="11" fill="#000">N(t)</text>
  <text x="6" y="105" font-family="Georgia,serif" font-size="10" fill="#000">atoms</text>

  <!-- y-axis labels at N₀, N₀/2, N₀/4, N₀/8 -->
  <!-- N₀ at y=80: -->
  <line x1="64" y1="80"  x2="74" y2="80"  stroke="#000" stroke-width="2"/>
  <text x="20" y="84"  font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">N₀</text>
  <!-- N₀/2 at y=160 -->
  <line x1="64" y1="160" x2="74" y2="160" stroke="#000" stroke-width="2"/>
  <text x="14" y="164" font-family="Georgia,serif" font-size="10" fill="#000">N₀/2</text>
  <!-- N₀/4 at y=232 (y=80+152*1/4*... actually linear in y, not N: 80+(390-80)*n where n is fraction -->
  <!-- y = 80 + (390-80)*(1 - N/N₀) ... let y=80+(390-80)*(1-N/N0) for N/N0=1/2 → y=80+155=235 -->
  <line x1="64" y1="235" x2="74" y2="235" stroke="#000" stroke-width="2"/>
  <text x="14" y="239" font-family="Georgia,serif" font-size="10" fill="#000">N₀/4</text>
  <!-- N₀/8 at y=80+310*7/8=352 -->
  <line x1="64" y1="312" x2="74" y2="312" stroke="#000" stroke-width="2"/>
  <text x="14" y="316" font-family="Georgia,serif" font-size="10" fill="#000">N₀/8</text>
  <!-- N₀/16 -->
  <line x1="64" y1="351" x2="74" y2="351" stroke="#000" stroke-width="2"/>
  <text x="8"  y="355" font-family="Georgia,serif" font-size="10" fill="#000">N₀/16</text>

  <!-- x-axis labels at t½ multiples -->
  <!-- t½ intervals spaced 100px apart: 0=70, t½=170, 2t½=270, 3t½=370, 4t½=470 -->
  <line x1="70"  y1="384" x2="70"  y2="394" stroke="#000" stroke-width="2"/><text x="67"  y="406" font-family="Georgia,serif" font-size="10" fill="#000">0</text>
  <line x1="170" y1="384" x2="170" y2="394" stroke="#000" stroke-width="2"/><text x="163" y="406" font-family="Georgia,serif" font-size="10" fill="#000">t½</text>
  <line x1="270" y1="384" x2="270" y2="394" stroke="#000" stroke-width="2"/><text x="261" y="406" font-family="Georgia,serif" font-size="10" fill="#000">2t½</text>
  <line x1="370" y1="384" x2="370" y2="394" stroke="#000" stroke-width="2"/><text x="361" y="406" font-family="Georgia,serif" font-size="10" fill="#000">3t½</text>
  <line x1="470" y1="384" x2="470" y2="394" stroke="#000" stroke-width="2"/><text x="461" y="406" font-family="Georgia,serif" font-size="10" fill="#000">4t½</text>

  <!-- ── DECAY CURVE ──
       N/N₀ = (1/2)^(t/t½)
       y_plot = 80 + 310 * (1 - N/N₀)
       At t=0:   N/N₀=1,   y=80
       At t=t½:  N/N₀=0.5, y=80+155=235
       At t=2t½: N/N₀=0.25, y=80+232=312
       At t=3t½: N/N₀=0.125, y=80+271=351
       At t=4t½: N/N₀=0.0625, y=80+290=370
       Using cubic bezier to approximate exponential
  ── -->
  <path d="M 70,80 C 120,80 155,155 170,235 C 185,315 230,340 270,352 C 310,364 350,368 370,371 C 390,374 430,376 470,378 C 490,379 510,380 530,381"
        fill="none" stroke="#000" stroke-width="3.5" stroke-linecap="round"/>

  <!-- ── HALF-LIFE STEP MARKINGS ── -->
  <!-- Step 1: N₀ → N₀/2 at t½ -->
  <line x1="70"  y1="80"  x2="70"  y2="235" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <line x1="70"  y1="235" x2="170" y2="235" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <line x1="170" y1="235" x2="170" y2="390" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <!-- Δy arrow for step 1 -->
  <line x1="50" y1="80"  x2="50" y2="235" stroke="#000" stroke-width="2"/>
  <polygon points="46,90 50,80 54,90" fill="#000"/>
  <polygon points="46,225 50,235 54,225" fill="#000"/>
  <text x="26" y="162" font-family="Georgia,serif" font-size="10" fill="#000">N₀/2</text>

  <!-- Step 2: N₀/2 → N₀/4 at 2t½ -->
  <line x1="170" y1="235" x2="270" y2="235" stroke="#000" stroke-width="1" stroke-dasharray="4,3"/>
  <line x1="270" y1="235" x2="270" y2="352" stroke="#000" stroke-width="1.5" stroke-dasharray="4,3"/>
  <line x1="270" y1="352" x2="270" y2="390" stroke="#000" stroke-width="1.5" stroke-dasharray="4,3"/>

  <!-- Step 3: at 3t½ -->
  <line x1="270" y1="352" x2="370" y2="352" stroke="#000" stroke-width="1" stroke-dasharray="4,3"/>
  <line x1="370" y1="352" x2="370" y2="371" stroke="#000" stroke-width="1" stroke-dasharray="4,3"/>
  <line x1="370" y1="371" x2="370" y2="390" stroke="#000" stroke-width="1" stroke-dasharray="4,3"/>

  <!-- Data dots at each t½ -->
  <circle cx="70"  cy="80"  r="6" fill="#000"/>
  <circle cx="170" cy="235" r="6" fill="#000"/>
  <circle cx="270" cy="352" r="6" fill="#000"/>
  <circle cx="370" cy="371" r="5" fill="#000"/>
  <circle cx="470" cy="378" r="5" fill="#000"/>

  <!-- Tangent line at t=0 showing initial slope (−λN₀) -->
  <line x1="70" y1="80" x2="200" y2="322" stroke="#000" stroke-width="1.5" stroke-dasharray="4,2"/>
  <text x="168" y="310" font-family="Georgia,serif" font-size="9" fill="#000">slope = −λN₀</text>

  <!-- Mean life τ = 1/λ annotation -->
  <!-- τ = t½/ln2 ≈ 1.443 t½ → x = 70+144=214, N/N₀=1/e≈0.368 → y=80+310*(1-0.368)=80+196=276 -->
  <circle cx="214" cy="276" r="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <line x1="214" y1="276" x2="260" y2="250" stroke="#000" stroke-width="1.5"/>
  <text x="262" y="248" font-family="Georgia,serif" font-size="10" fill="#000">N₀/e  at t=τ=1/λ</text>
  <line x1="214" y1="276" x2="214" y2="390" stroke="#000" stroke-width="1" stroke-dasharray="3,3"/>
  <text x="198" y="406" font-family="Georgia,serif" font-size="9" fill="#000">τ</text>

  <!-- ── Formula box ── -->
  <rect x="30" y="425" width="500" height="48" rx="5" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="42" y="442" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">N(t) = N₀ e^(−λt)    A(t) = λN(t) = A₀ e^(−λt)</text>
  <text x="42" y="457" font-family="Georgia,serif" font-size="10" fill="#000">t½ = ln2/λ = 0.693/λ    Mean life τ = 1/λ = t½/ln2    ΔN/Δt = −λN</text>
  <text x="42" y="469" font-family="Georgia,serif" font-size="10" fill="#000">After n half-lives: N = N₀/2ⁿ   Activity A in Bq (= disintegrations/s)</text>
</svg>`;

