// ─── 6. MERSENNE'S LAWS — TENSION, LENGTH, FREQUENCY ──────────────────────
static mersennesLawsTensionLengthFrequencyRelationshipDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 420">

  <!-- Title -->
  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Mersenne's Laws — Tension, Length and Frequency</text>

  <!-- Central formula box -->
  <rect x="160" y="35" width="240" height="55" rx="6" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="196" y="58" font-family="Georgia,serif" font-size="15" font-weight="bold" fill="#000">f = (1/2L)√(T/μ)</text>
  <text x="178" y="78" font-family="Georgia,serif" font-size="10" fill="#000">f: frequency   L: length   T: tension   μ: linear density</text>

  <!-- ═══ LAW 1: f ∝ 1/L ═══ -->
  <text x="30" y="120" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Law 1:  f ∝ 1/L  (T, μ constant)</text>

  <!-- String 1 (full length L) -->
  <rect x="40"  y="135" width="8" height="30" fill="#000"/>
  <rect x="278" y="135" width="8" height="30" fill="#000"/>
  <line x1="48" y1="150" x2="278" y2="150" stroke="#000" stroke-width="4" stroke-linecap="round"/>
  <text x="148" y="145" font-family="Georgia,serif" font-size="10" fill="#000">L → f₁</text>

  <!-- String 2 (half length L/2) -->
  <rect x="40"  y="175" width="8" height="24" fill="#000"/>
  <rect x="158" y="175" width="8" height="24" fill="#000"/>
  <line x1="48" y1="187" x2="158" y2="187" stroke="#000" stroke-width="4" stroke-linecap="round"/>
  <text x="78" y="182" font-family="Georgia,serif" font-size="10" fill="#000">L/2 → 2f₁</text>

  <!-- Arrow showing inverse relationship -->
  <text x="310" y="165" font-family="Georgia,serif" font-size="11" fill="#000">Halve L ⟹ double f</text>

  <!-- ═══ LAW 2: f ∝ √T ═══ -->
  <text x="30" y="225" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Law 2:  f ∝ √T  (L, μ constant)</text>

  <!-- String under low tension (sags more) -->
  <rect x="40"  y="238" width="8" height="30" fill="#000"/>
  <rect x="278" y="238" width="8" height="30" fill="#000"/>
  <path d="M 48,248 Q 163,280 278,248" fill="none" stroke="#000" stroke-width="4" stroke-linecap="round"/>
  <text x="120" y="288" font-family="Georgia,serif" font-size="10" fill="#000">Low T → low f</text>
  <!-- Tension weight -->
  <line x1="283" y1="253" x2="283" y2="275" stroke="#000" stroke-width="2"/>
  <rect x="274" y="275" width="18" height="14" fill="none" stroke="#000" stroke-width="2"/>
  <text x="278" y="286" font-family="Georgia,serif" font-size="8" fill="#000">T₁</text>

  <!-- String under high tension (straighter) -->
  <rect x="40"  y="305" width="8" height="30" fill="#000"/>
  <rect x="278" y="305" width="8" height="30" fill="#000"/>
  <line x1="48" y1="320" x2="278" y2="320" stroke="#000" stroke-width="4" stroke-linecap="round"/>
  <text x="120" y="315" font-family="Georgia,serif" font-size="10" fill="#000">High T → high f</text>
  <!-- Tension weight -->
  <line x1="283" y1="320" x2="283" y2="345" stroke="#000" stroke-width="2"/>
  <rect x="274" y="345" width="18" height="20" fill="none" stroke="#000" stroke-width="2"/>
  <text x="278" y="359" font-family="Georgia,serif" font-size="8" fill="#000">4T₁</text>
  <text x="310" y="335" font-family="Georgia,serif" font-size="11" fill="#000">4× T ⟹ 2× f</text>

  <!-- ═══ LAW 3: f ∝ 1/√μ ═══ -->
  <text x="30" y="388" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Law 3:  f ∝ 1/√μ  (L, T constant)</text>
  <text x="30" y="404" font-family="Georgia,serif" font-size="10" fill="#000">Thicker/denser string (larger μ) ⟹ lower frequency (deeper note)</text>

  <!-- Info box -->
  <rect x="370" y="380" width="170" height="32" rx="4" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="4,3"/>
  <text x="380" y="395" font-family="Georgia,serif" font-size="10" fill="#000">4× μ ⟹ f halved</text>
  <text x="380" y="408" font-family="Georgia,serif" font-size="10" fill="#000">μ = mass per unit length</text>
</svg>`;

